package main

import (
	"log"
	"net/http"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	requests = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "app_requests_total",
			Help: "Total number of requests processed by the application.",
		},
		[]string{"user", "endpoint"},
	)
)

func init() {
	prometheus.MustRegister(requests)
}

func recordMetrics(user, endpoint string) {
	requests.With(prometheus.Labels{"user": user, "endpoint": endpoint}).Inc()
}

func handler(w http.ResponseWriter, r *http.Request) {
	user := r.URL.Query().Get("user")
	endpoint := r.URL.Path
	if user == "" {
		http.Error(w, "User parameter is required", http.StatusBadRequest)
		return
	}
	recordMetrics(user, endpoint)
	w.Write([]byte("Request processed"))
}

func main() {
	http.Handle("/metrics", promhttp.Handler())
	http.HandleFunc("/", handler)

	log.Println("Starting server on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}